using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Configuration ──────────────────────────────────────────────────────────────
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ── Tools ──────────────────────────────────────────────────────────────────────
var notebook = new Notebook();
var webSearch = new WebSearcher();

var tools = new AIFunction[]
{
    AIFunctionFactory.Create(webSearch.SearchWeb),
    AIFunctionFactory.Create(notebook.SaveNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// ── Chat client with automatic function invocation ─────────────────────────────
IChatClient client = new ChatClientBuilder(
        new OpenAIClient(openAiKey).GetChatClient(model).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions { Tools = [.. tools] };

var systemPrompt = """
    You are a research agent. When the user gives you a topic:
    1. Search the web for relevant information (make 2-3 searches with varied queries).
    2. Save important findings as notes using the note-taking tool.
    3. After gathering enough information, retrieve all your notes and produce a
       well-structured summary with key facts, organized under clear headings.
    Always cite search results where possible.
    """;

var history = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
};

// ── Interactive loop ───────────────────────────────────────────────────────────
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        🔍  Research Agent  (AI)         ║");
Console.WriteLine("╠══════════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research, or 'quit'.  ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic ▸ ");
    Console.ResetColor();

    var input = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(input))
        continue;
    if (input.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notebook.Clear();
    history.Add(new ChatMessage(ChatRole.User, $"Research the following topic: {input}"));

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("\n⏳ Researching…\n");
    Console.ResetColor();

    var response = await client.GetResponseAsync(history, chatOptions);
    history.AddRange(response.Messages);

    Console.ForegroundColor = ConsoleColor.Green;
    Console.WriteLine("── Summary ────────────────────────────────");
    Console.ResetColor();
    Console.WriteLine(response.Text);
    Console.WriteLine();
}

