/// <summary>Searches the web using the Brave Search API or falls back to DuckDuckGo.</summary>
sealed class WebSearcher
{
    private readonly HttpClient _http = new();
    private readonly string? _braveApiKey = Environment.GetEnvironmentVariable("BRAVE_API_KEY");

    [Description("Search the web for information on a query. Returns a list of result snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.ForegroundColor = ConsoleColor.Yellow;
        Console.WriteLine($"  🌐 Searching: \"{query}\"");
        Console.ResetColor();

        try
        {
            if (!string.IsNullOrEmpty(_braveApiKey))
                return await BraveSearch(query);

            return await DuckDuckGoSearch(query);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private async Task<string> BraveSearch(string query)
    {
        var url = $"https://api.search.brave.com/res/v1/web/search?q={Uri.EscapeDataString(query)}&count=5";
        using var request = new HttpRequestMessage(HttpMethod.Get, url);
        request.Headers.Add("X-Subscription-Token", _braveApiKey);
        request.Headers.Add("Accept", "application/json");

        var resp = await _http.SendAsync(request);
        resp.EnsureSuccessStatusCode();

        using var doc = JsonDocument.Parse(await resp.Content.ReadAsStringAsync());
        var sb = new StringBuilder();
        if (doc.RootElement.TryGetProperty("web", out var web) &&
            web.TryGetProperty("results", out var results))
        {
            foreach (var r in results.EnumerateArray().Take(5))
            {
                var title = r.GetProperty("title").GetString();
                var snippet = r.TryGetProperty("description", out var d) ? d.GetString() : "";
                var link = r.GetProperty("url").GetString();
                sb.AppendLine($"- **{title}**: {snippet} ({link})");
            }
        }

        return sb.Length > 0 ? sb.ToString() : "No results found.";
    }

    private async Task<string> DuckDuckGoSearch(string query)
    {
        var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
        using var request = new HttpRequestMessage(HttpMethod.Get, url);
        request.Headers.Add("User-Agent", "ResearchAgent/1.0");

        var resp = await _http.SendAsync(request);
        resp.EnsureSuccessStatusCode();

        var html = await resp.Content.ReadAsStringAsync();
        var sb = new StringBuilder();
        int count = 0;

        // Simple parsing of DuckDuckGo HTML results
        var snippetTag = "class=\"result__snippet\"";
        var titleTag = "class=\"result__a\"";
        int pos = 0;

        while (count < 5 && (pos = html.IndexOf(titleTag, pos, StringComparison.Ordinal)) >= 0)
        {
            pos += titleTag.Length;
            var title = ExtractTagContent(html, pos);

            var snippetPos = html.IndexOf(snippetTag, pos, StringComparison.Ordinal);
            var snippet = snippetPos >= 0 ? ExtractTagContent(html, snippetPos + snippetTag.Length) : "";

            if (!string.IsNullOrWhiteSpace(title))
            {
                sb.AppendLine($"- **{WebUtility.HtmlDecode(title.Trim())}**: {WebUtility.HtmlDecode(snippet.Trim())}");
                count++;
            }
        }

        return sb.Length > 0 ? sb.ToString() : "No results found.";
    }

    private static string ExtractTagContent(string html, int startAfterTag)
    {
        var gt = html.IndexOf('>', startAfterTag);
        if (gt < 0) return "";
        var lt = html.IndexOf('<', gt);
        if (lt < 0) return "";
        return html[(gt + 1)..lt];
    }
}

/// <summary>In-memory notebook for the agent to save and retrieve research notes.</summary>
sealed class Notebook
{
    private readonly List<string> _notes = [];

    [Description("Save an important research finding as a note for later reference.")]
    public string SaveNote(
        [Description("The note text to save")] string note)
    {
        _notes.Add(note);
        Console.ForegroundColor = ConsoleColor.Magenta;
        Console.WriteLine($"  📝 Note #{_notes.Count} saved");
        Console.ResetColor();
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieve all saved research notes collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
            sb.AppendLine($"Note #{i + 1}: {_notes[i]}");
        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

